👉 Minimum working approach:
<button id="revealBtn">Click to reveal</button>
<p id="funFact" class="hidden">javascript checkpoint complete</p>
<style>
  .hidden { display: none; }
</style>
<script>
  const btn = document.querySelector("#revealBtn");
  const fact = document.querySelector("#funFact");
  btn.addEventListener("click", function() {
    fact.classList.toggle("hidden");
    console.log("javascript checkpoint complete");
  });
</script>
